package spike

import (
	"testing"

	"github.com/modelcontextprotocol/go-sdk/mcp"
)

// TestMCPSDKStructuredContent validates that the Go MCP SDK supports structuredContent.
func TestMCPSDKStructuredContent(t *testing.T) {
	// Verify that CallToolResult has StructuredContent field
	result := &mcp.CallToolResult{
		Content: []mcp.Content{
			&mcp.TextContent{Text: "test"},
		},
		StructuredContent: map[string]any{
			"type": "testResponse",
			"data": "value",
		},
	}

	if result.StructuredContent == nil {
		t.Error("StructuredContent field should be available")
	}
	t.Log("PASS: structuredContent is supported in Go MCP SDK")
}

// TestMCPSDKServerCreation validates basic server creation.
func TestMCPSDKServerCreation(t *testing.T) {
	server := mcp.NewServer(&mcp.Implementation{
		Name:    "test-server",
		Version: "0.1.0",
	}, nil)

	if server == nil {
		t.Fatal("NewServer returned nil")
	}
	t.Log("PASS: MCP server can be created")
}

// TestMCPSDKToolRegistration validates tool registration with AddTool.
func TestMCPSDKToolRegistration(t *testing.T) {
	server := mcp.NewServer(&mcp.Implementation{
		Name:    "test-server",
		Version: "0.1.0",
	}, nil)

	type TestArgs struct {
		Query string `json:"query"`
	}

	// This should not panic
	mcp.AddTool(server, &mcp.Tool{
		Name:        "test_tool",
		Description: "A test tool",
	}, func(ctx __import_context.Context, req *mcp.CallToolRequest, args TestArgs) (*mcp.CallToolResult, any, error) {
		return &mcp.CallToolResult{
			Content: []mcp.Content{
				&mcp.TextContent{Text: "hello"},
			},
		}, nil, nil
	})

	t.Log("PASS: Tool registration works with typed args")
}
